import{_ as r,o as t,c as e,ai as o,aj as p}from"./chunks/framework.LAMr6Wp9.js";const g=JSON.parse('{"title":"应用架构","description":"","frontmatter":{"title":"应用架构","order":0},"headers":[],"relativePath":"ai/app/arch/index.md","filePath":"ai/app/arch/index.md"}'),n={name:"ai/app/arch/index.md"};function s(i,a,c,l,_,d){return t(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="应用架构" tabindex="-1">应用架构 <a class="header-anchor" href="#应用架构" aria-label="Permalink to “应用架构”">​</a></h1><p>大模型应用开发的核心特点之一是在榨干模型泛化潜力的同时，约束模型的不确定性。</p><h2 id="架构层次" tabindex="-1">架构层次 <a class="header-anchor" href="#架构层次" aria-label="Permalink to “架构层次”">​</a></h2><p><img src="'+p+'" alt="arch"></p><p>一个成熟的 LLM 应用架构通常包含以下层次：</p><p><strong>客户端层</strong>处理用户输入、流式渲染、状态管理。基于传统的前端 UI 技术，或者结合前沿领域的生成式 UI。</p><p><strong>API 网关层</strong>统一入口，负责认证鉴权、限流计费、请求路由。网关对外暴露 OpenAI 兼容协议，对内代理到不同模型提供商。这一层使得应用代码不需要关心底层模型的变化。</p><p><strong>路由层</strong>根据请求内容选择最合适的模型。路由策略可以是基于规则的（关键词匹配 → 小模型，复杂推理 → 大模型），也可以是基于模型的（用小模型判断任务复杂度，再路由到对应模型）。</p><p><strong>缓存层</strong>拦截重复或相似的请求，直接返回缓存结果。语义缓存通过向量相似度匹配&quot;意思相近&quot;的问题，比精确匹配的缓存命中率高得多。</p><p><strong>模型服务层</strong>执行实际的 LLM 推理。可以是自建的 vLLM/Ollama 服务，也可以是云端 API（OpenAI、Anthropic、Google）。每个模型有独立的健康检查和性能指标。</p><p><strong>可观测层</strong>贯穿所有层次，记录每次请求的完整链路（输入→路由→模型→输出），用于质量评估、成本追踪和故障排查。这一层在 <a href="/ai/app/overlay/ops/">LLMOps</a> 中详细讨论。</p>',11)])])}const m=r(n,[["render",s]]);export{g as __pageData,m as default};
